(() => {
  "use strict";

  const englishLessons = window.HomeSchoolLessonModules?.english?.[5];
  if (!Array.isArray(englishLessons) || !englishLessons.length) return;

  const lessonPayloadBase64 = "";

  const lessonIndex = englishLessons.findIndex((lesson, index) => (
    index === 0
    || String(lesson?.id || "").trim() === "english_5_1"
    || String(lesson?.key || "").trim() === "lesson_1"
    || String(lesson?.key || "").trim() === "reading"
  ));
  if (lessonIndex < 0) return;

  let nextLesson = null;
  try {
    const binary = atob(lessonPayloadBase64);
    const bytes = Uint8Array.from(binary, (char) => char.charCodeAt(0));
    nextLesson = JSON.parse(new TextDecoder().decode(bytes));
  } catch (error) {
    console.error("Failed to load Grade 5 English lesson 1 payload", error);
    return;
  }

  if (!nextLesson || typeof nextLesson !== "object") return;

  const previousLesson = englishLessons[lessonIndex] || {};
  englishLessons[lessonIndex] = {
    ...nextLesson,
    key: "lesson_1",
    id: String(previousLesson?.id || "").trim() || "english_5_1",
  };
})();

